/* ZENTEA – Hero background image (base64)
   Tách riêng vì kích thước lớn (962KB)
*/
const IMG_B64 = "";
document.addEventListener('DOMContentLoaded', function(){
  const heroBg = document.getElementById('heroBg');
  if(heroBg) heroBg.style.backgroundImage = 'url(data:image/jpeg;base64,' + IMG_B64 + ')';
});
